#!/usr/bin/env node
/**
 * Post-process the Postman collection generated by `openapi-to-postmanv2` from
 * docs/api/openapi.yaml, so `npm run api:postman` produces a ready-to-use file:
 *   - collection-level Bearer auth via the {{bearerToken}} variable,
 *   - {{baseUrl}} + {{bearerToken}} variables with local-dev defaults,
 *   - read endpoints (GET) + the public feed / health / test page marked `noauth`
 *     so the bearer never rides on an unauthenticated call.
 *
 * It ALSO strips the generator's non-deterministic ids (`_postman_id` + the per-item
 * `id` UUIDs that `openapi-to-postmanv2` re-randomises every run) so the output is
 * byte-stable: re-running `npm run api:postman` on an unchanged spec yields a clean
 * `git diff`. That lets CI gate spec↔collection drift with `git diff --exit-code`.
 * The ids are optional in the collection schema (Postman re-mints them on import).
 *
 * Run via `npm run api:postman` — do NOT hand-edit the generated JSON.
 */
import { readFileSync, writeFileSync } from 'node:fs';

const PATH = 'docs/api/dealroute.postman_collection.json';
const c = JSON.parse(readFileSync(PATH, 'utf8'));

// 0. Strip the generator's random ids so the file is byte-stable (see header).
function stripIds(node) {
  if (Array.isArray(node)) {
    node.forEach(stripIds);
  } else if (node && typeof node === 'object') {
    delete node._postman_id;
    if (typeof node.id === 'string' && /^[0-9a-f-]{36}$/.test(node.id)) delete node.id;
    Object.values(node).forEach(stripIds);
  }
}
stripIds(c);

// 1. Collection-level bearer auth (inherited by requests unless overridden below).
c.auth = { type: 'bearer', bearer: [{ key: 'token', value: '{{bearerToken}}', type: 'string' }] };

// 2. Variables with local-dev defaults.
const vars = new Map((c.variable ?? []).map((v) => [v.key, v]));
vars.set('baseUrl', { key: 'baseUrl', value: 'http://localhost:3000', type: 'string' });
vars.set('bearerToken', { key: 'bearerToken', value: 'local-dev-token', type: 'string' });
c.variable = [...vars.values()];

// 3. Unauthenticated surfaces: never attach the bearer to a public/read call.
const NOAUTH_FOLDERS = new Set(['Public feed', 'Health', 'Test page']);
function walk(items, folderName) {
  for (const it of items) {
    if (it.item) {
      walk(it.item, it.name);
      continue;
    }
    const method = it.request?.method ?? 'GET';
    if (NOAUTH_FOLDERS.has(folderName) || method === 'GET') {
      it.request = it.request ?? {};
      it.request.auth = { type: 'noauth' };
    }
  }
}
walk(c.item ?? [], '(root)');

// 4. Keep-in-sync nudge.
const note =
  'Generated from docs/api/openapi.yaml — regenerate with `npm run api:postman` when the ' +
  'spec changes; do not hand-edit. Set {{bearerToken}} to your REVIEW_API_TOKEN.';
c.info.description = c.info.description ? `${c.info.description}\n\n${note}` : note;

writeFileSync(PATH, JSON.stringify(c, null, 2) + '\n');
console.log(`postman-finalize: bearer auth + variables applied → ${PATH}`);
